{"language":"Solidity","sources":{"DocumentRegistry.sol":{"content":"// SPDX-License-Identifier: MIT
pragma solidity ^0.8.0;

contract DocumentRegistry {
    struct Document {
        address owner;
        uint256 timestamp;
    }

    mapping(string => Document) private documents;

    event DocumentRegistered(string indexed docHash, address indexed owner, uint256 timestamp);

    function registerDocument(string calldata docHash) external {
        require(bytes(docHash).length == 64, "Invalid SHA-256 hash");
        require(documents[docHash].timestamp == 0, "Document already registered");

        documents[docHash] = Document({
            owner: msg.sender,
            timestamp: block.timestamp
        });

        emit DocumentRegistered(docHash, msg.sender, block.timestamp);
    }

    function verifyDocument(string calldata docHash) external view returns (bool exists, address owner, uint256 timestamp) {
        Document memory doc = documents[docHash];
        exists = doc.timestamp != 0;
        owner = doc.owner;
        timestamp = doc.timestamp;
    }
}
